CREATE TYPE "SubscriptionOrderStatus" AS ENUM ('CREATED', 'PENDING_PAYMENT', 'PENDING_REVIEW', 'COMPLETED', 'EXPIRED', 'CANCELLED');
CREATE TYPE "SubscriptionPaymentStatus" AS ENUM ('PENDING_PAYMENT', 'PENDING_REVIEW', 'APPROVED', 'REJECTED', 'EXPIRED', 'CANCELLED');
CREATE TYPE "SubscriptionPaymentMethodCode" AS ENUM ('MOTO_EXPRESS', 'BANK_TRANSFER');
ALTER TABLE "RiderSubscription" ADD COLUMN "paymentId" TEXT, ADD COLUMN "planId" TEXT;
CREATE TABLE "SubscriptionPlan" ("id" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT NOT NULL,"price" DECIMAL(10,2) NOT NULL,"currency" TEXT NOT NULL DEFAULT 'NIO',"durationDays" INTEGER NOT NULL,"benefits" JSONB NOT NULL,"isActive" BOOLEAN NOT NULL DEFAULT true,"displayOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "SubscriptionPlan_pkey" PRIMARY KEY ("id"));
CREATE TABLE "PaymentMethodConfig" ("id" TEXT NOT NULL,"code" "SubscriptionPaymentMethodCode" NOT NULL,"name" TEXT NOT NULL,"instructions" TEXT NOT NULL,"isActive" BOOLEAN NOT NULL DEFAULT true,"configuration" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "PaymentMethodConfig_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SubscriptionOrder" ("id" TEXT NOT NULL,"riderId" TEXT NOT NULL,"planId" TEXT NOT NULL,"planNameSnapshot" TEXT NOT NULL,"priceSnapshot" DECIMAL(10,2) NOT NULL,"currencySnapshot" TEXT NOT NULL,"durationDaysSnapshot" INTEGER NOT NULL,"status" "SubscriptionOrderStatus" NOT NULL DEFAULT 'CREATED',"expiresAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "SubscriptionOrder_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Payment" ("id" TEXT NOT NULL,"orderId" TEXT NOT NULL,"methodId" TEXT NOT NULL,"amount" DECIMAL(10,2) NOT NULL,"currency" TEXT NOT NULL,"status" "SubscriptionPaymentStatus" NOT NULL DEFAULT 'PENDING_PAYMENT',"externalReference" TEXT NOT NULL,"customerReference" TEXT,"proofReference" TEXT,"metadata" JSONB,"submittedAt" TIMESTAMP(3),"reviewedAt" TIMESTAMP(3),"reviewedByAdminId" TEXT,"rejectionReason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Payment_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "SubscriptionPlan_code_key" ON "SubscriptionPlan"("code"); CREATE INDEX "SubscriptionPlan_isActive_displayOrder_idx" ON "SubscriptionPlan"("isActive","displayOrder"); CREATE UNIQUE INDEX "PaymentMethodConfig_code_key" ON "PaymentMethodConfig"("code"); CREATE INDEX "SubscriptionOrder_riderId_status_idx" ON "SubscriptionOrder"("riderId","status"); CREATE INDEX "SubscriptionOrder_status_expiresAt_idx" ON "SubscriptionOrder"("status","expiresAt"); CREATE UNIQUE INDEX "Payment_orderId_key" ON "Payment"("orderId"); CREATE UNIQUE INDEX "Payment_externalReference_key" ON "Payment"("externalReference"); CREATE INDEX "Payment_status_createdAt_idx" ON "Payment"("status","createdAt"); CREATE INDEX "Payment_methodId_status_idx" ON "Payment"("methodId","status"); CREATE UNIQUE INDEX "RiderSubscription_paymentId_key" ON "RiderSubscription"("paymentId");
ALTER TABLE "RiderSubscription" ADD CONSTRAINT "RiderSubscription_planId_fkey" FOREIGN KEY ("planId") REFERENCES "SubscriptionPlan"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "RiderSubscription" ADD CONSTRAINT "RiderSubscription_paymentId_fkey" FOREIGN KEY ("paymentId") REFERENCES "Payment"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "SubscriptionOrder" ADD CONSTRAINT "SubscriptionOrder_riderId_fkey" FOREIGN KEY ("riderId") REFERENCES "RiderProfile"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "SubscriptionOrder" ADD CONSTRAINT "SubscriptionOrder_planId_fkey" FOREIGN KEY ("planId") REFERENCES "SubscriptionPlan"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Payment" ADD CONSTRAINT "Payment_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "SubscriptionOrder"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Payment" ADD CONSTRAINT "Payment_methodId_fkey" FOREIGN KEY ("methodId") REFERENCES "PaymentMethodConfig"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
